namespace sv_2028240766a149c583a2a3c849e40194.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public sealed class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#1b6ec2";

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>Raised whenever Theme or AccentColor changes.</summary>
    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

// Applies the theme to the document root so CSS custom properties and
// data-attributes take effect across the entire page (including static SSR areas).
export function applyTheme(theme, accentColor) {
    const root = document.documentElement;

    root.setAttribute("data-theme", theme.toLowerCase());
    root.style.setProperty("--accent-color", accentColor);
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService
@inject IJSRuntime JS

<span class="theme-indicator" style="color: @ThemeService.AccentColor;">
    @ThemeIcon @ThemeService.Theme
</span>

@code {
    private IJSObjectReference? _module;

    private string ThemeIcon => ThemeService.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/theme.js");
        }

        // Push theme to the DOM on every render so the static layout stays in sync.
        if (_module is not null)
        {
            await _module.InvokeVoidAsync(
                "applyTheme",
                ThemeService.Theme.ToString(),
                ThemeService.AccentColor);
        }
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Toggle theme">
    @ThemeIcon
</button>

@code {
    private string ThemeIcon => ThemeService.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 480px;">
    <h5>Theme</h5>
    <div class="btn-group mb-3" role="group">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <button class="btn @(t == ThemeService.Theme ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => ThemeService.Theme = t">
                @t
            </button>
        }
    </div>

    <h5>Accent Color</h5>
    <div class="d-flex align-items-center gap-3 mb-3">
        <input type="color" class="form-control form-control-color"
               value="@ThemeService.AccentColor"
               @onchange="OnAccentColorChanged" />
        <span style="color: @ThemeService.AccentColor; font-weight: bold;">
            @ThemeService.AccentColor
        </span>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#1b6ec2";
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

