html, body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
}

/* Theme custom properties */
:root,
[data-theme="light"] {
    --bg-color: #ffffff;
    --text-color: #1a1a1a;
    --top-row-bg: #f7f7f7;
    --top-row-border: #d6d5d5;
    --accent-color: #1b6ec2;
}

[data-theme="dark"] {
    --bg-color: #1a1a2e;
    --text-color: #e0e0e0;
    --top-row-bg: #16213e;
    --top-row-border: #0f3460;
    --accent-color: #1b6ec2;
}

[data-theme="system"] {
    --bg-color: #ffffff;
    --text-color: #1a1a1a;
    --top-row-bg: #f7f7f7;
    --top-row-border: #d6d5d5;
    --accent-color: #1b6ec2;
}

@media (prefers-color-scheme: dark) {
    [data-theme="system"] {
        --bg-color: #1a1a2e;
        --text-color: #e0e0e0;
        --top-row-bg: #16213e;
        --top-row-border: #0f3460;
    }
}

body {
    background-color: var(--bg-color);
    color: var(--text-color);
    transition: background-color 0.3s, color 0.3s;
}

a, .btn-link {
    color: var(--accent-color, #006bb7);
}

